import threading
from functools import wraps


def debounce(wait_seconds: float):
    def decorator(func):
        lock = threading.Lock()
        timer = {"t": None}

        @wraps(func)
        def wrapper(*args, **kwargs):
            with lock:
                if timer["t"] is not None:
                    timer["t"].cancel()
                timer["t"] = threading.Timer(
                    wait_seconds, lambda: func(*args, **kwargs)
                )
                timer["t"].daemon = True
                timer["t"].start()

        return wrapper

    return decorator
```

